// ============================================================
// config/database.js
// Secure database configuration - uses dedicated app user, NOT superuser
// ============================================================

const { Pool } = require('pg');

function validateDatabaseConfig(config) {
    const FORBIDDEN_SUPERUSERS = ['postgres', 'admin', 'root', 'superuser', 'pg_admin'];

    if (!config.user) {
        throw new Error('Database user must be specified');
    }

    if (FORBIDDEN_SUPERUSERS.includes(config.user.toLowerCase())) {
        throw new Error(
            `SECURITY VIOLATION: Refusing to connect as '${config.user}'. ` +
            `Application must use a dedicated, least-privilege database role. ` +
            `Never use superuser accounts (${FORBIDDEN_SUPERUSERS.join(', ')}) for application connections. ` +
            `Create a dedicated role with only SELECT, INSERT, UPDATE, DELETE permissions.`
        );
    }

    if (!config.password || config.password.length < 16) {
        throw new Error('Database password must be at least 16 characters for application roles');
    }

    if (config.ssl === false && config.host !== 'localhost' && config.host !== '127.0.0.1') {
        throw new Error('SSL must be enabled for non-localhost database connections');
    }

    return true;
}

function createDatabasePool() {
    const config = {
        user: process.env.DB_USER,                          // e.g., 'app_service_user'
        password: process.env.DB_PASSWORD,
        host: process.env.DB_HOST || 'localhost',
        port: parseInt(process.env.DB_PORT, 10) || 5432,
        database: process.env.DB_NAME || 'app_database',
        max: parseInt(process.env.DB_POOL_MAX, 10) || 15,   // Connection pool size
        idleTimeoutMillis: 30000,
        connectionTimeoutMillis: 5000,
        statement_timeout: 30000,                            // 30s query timeout
        query_timeout: 30000,
        application_name: 'backend-api-service',
    };

    // Enable SSL for non-local connections
    if (process.env.DB_HOST && process.env.DB_HOST !== 'localhost' && process.env.DB_HOST !== '127.0.0.1') {
        config.ssl = {
            rejectUnauthorized: process.env.DB_SSL_REJECT_UNAUTHORIZED !== 'false',
            ca: process.env.DB_SSL_CA || undefined,
        };
    }

    // Validate before creating pool
    validateDatabaseConfig(config);

    const pool = new Pool(config);

    // Set search_path on each new connection to avoid schema injection
    pool.on('connect', (client) => {
        client.query('SET search_path TO app_schema, public');
    });

    pool.on('error', (err) => {
        console.error('Unexpected database pool error:', err.message);
    });

    return pool;
}

module.exports = { createDatabasePool, validateDatabaseConfig };


// ============================================================
// db/queryHelper.js
// Safe query helper with parameterized queries
// ============================================================

class QueryHelper {
    constructor(pool) {
        this.pool = pool;
    }

    async query(text, params = []) {
        const start = Date.now();
        try {
            const result = await this.pool.query(text, params);
            const duration = Date.now() - start;
            if (duration > 2000) {
                console.warn('Slow query detected:', { text, duration: `${duration}ms`, rows: result.rowCount });
            }
            return result;
        } catch (error) {
            console.error('Database query error:', { text: text.substring(0, 100), error: error.message });
            throw error;
        }
    }

    async getClient() {
        const client = await this.pool.connect();
        return client;
    }

    async transaction(callback) {
        const client = await this.pool.connect();
        try {
            await client.query('BEGIN');
            const result = await callback(client);
            await client.query('COMMIT');
            return result;
        } catch (error) {
            await client.query('ROLLBACK');
            throw error;
        } finally {
            client.release();
        }
    }

    async healthCheck() {
        try {
            const result = await this.query('SELECT NOW() AS server_time, current_user AS connected_as');
            const row = result.rows[0];

            // Verify we're NOT connected as superuser
            const superuserCheck = await this.query(
                'SELECT usesuper FROM pg_user WHERE usename = current_user'
            );

            if (superuserCheck.rows[0]?.usesuper === true) {
                throw new Error('SECURITY: Application is connected as a superuser. This is not allowed.');
            }

            return {
                healthy: true,
                serverTime: row.server_time,
                connectedAs: row.connected_as,
                isSuperuser: false,
            };
        } catch (error) {
            return { healthy: false, error: error.message };
        }
    }
}

module.exports = QueryHelper;


