class OrderModel {
    constructor(queryHelper) {
        this.db = queryHelper;
    }

    async findAll({ limit = 50, offset = 0, userId, status } = {}) {
        let query = `
            SELECT o.id, o.user_id, o.status, o.total_amount, o.created_at, o.updated_at,
                   u.username
            FROM orders o
            JOIN users u ON o.user_id = u.id
            WHERE 1=1`;
        const params = [];
        let paramIndex = 1;

        if (userId !== undefined) {
            query += ` AND o.user_id = $${paramIndex++}`;
            params.push(userId);
        }
        if (status !== undefined) {
            query += ` AND o.status = $${paramIndex++}`;
            params.push(status);
        }

        query += ` ORDER BY o.id DESC LIMIT $${paramIndex++} OFFSET $${paramIndex++}`;
        params.push(Math.min(limit, 100), offset);

        const result = await this.db.query(query, params);
        return result.rows;
    }

    async findById(id) {
        const orderResult = await this.db.query(
            `SELECT o.id, o.user_id, o.status, o.total_amount, o.created_at, o.updated_at,
                    u.username, u.email
             FROM orders o
             JOIN users u ON o.user_id = u.id
             WHERE o.id = $1`,
            [id]
        );

        if (orderResult.rows.length === 0) return null;

        const itemsResult = await this.db.query(
            `SELECT oi.id, oi.product_id, oi.quantity, oi.unit_price,
                    p.name AS product_name
             FROM order_items oi
             JOIN products p ON oi.product_id = p.id
             WHERE oi.order_id = $1
             ORDER BY oi.id`,
            [id]
        );

        return {
            ...orderResult.rows[0],
            items: itemsResult.rows,
        };
    }

    async create({ user_id, items }) {
        // Use a transaction to ensure atomicity
        return this.db.transaction(async (client) => {
            // Create the order
            const orderResult = await client.query(
                `INSERT INTO orders (user_id, status, total_amount)
                 VALUES ($1, 'pending', 0)
                 RETURNING id, user_id, status, total_amount, created_at, updated_at`,
                [user_id]
            );
            const order = orderResult.rows[0];

            let totalAmount = 0;
            const insertedItems = [];

            for (const item of items) {
                // Verify product exists and get price, also decrement stock
                const productResult = await client.query(
                    `UPDATE products
                     SET stock_quantity = stock_quantity - $2,
                         updated_at = NOW()
                     WHERE id = $1 AND stock_quantity >= $2
                     RETURNING id, name, price, stock_quantity`,
                    [item.product_id, item.quantity]
                );

                if (productResult.rows.length === 0) {
                    throw new Error(`Product ${item.product_id} not found or insufficient stock`);
                }

                const product = productResult.rows[0];
                const unitPrice = parseFloat(product.price);
                const lineTotal = unitPrice * item.quantity;
                totalAmount += lineTotal;

                const itemResult = await client.query(
                    `INSERT INTO order_items (order_id, product_id, quantity, unit_price)
                     VALUES ($1, $2, $3, $4)
                     RETURNING id, order_id, product_id, quantity, unit_price`,
                    [order.id, item.product_id, item.quantity, unitPrice]
                );

                insertedItems.push({
                    ...itemResult.rows[0],
                    product_name: product.name,
                });
            }

            // Update total amount
            await client.query(
                'UPDATE orders SET total_amount = $2, updated_at = NOW() WHERE id = $1',
                [order.id, totalAmount]
            );

            return {
                ...order,
                total_amount: totalAmount.toFixed(2),
                items: insertedItems,
            };
        });
    }

    async updateStatus(id, status) {
        const validStatuses = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
        if (!validStatuses.includes(status)) {
            throw new Error(`Invalid status: ${status}. Must be one of: ${validStatuses.join(', ')}`);
        }

        const result = await this.db.query(
            `UPDATE orders
             SET status = $2, updated_at = NOW()
             WHERE id = $1
             RETURNING id, user_id, status, total_amount, created_at, updated_at`,
            [id, status]
        );
        return result.rows[0] || null;
    }

    async delete(id) {
        // Restore stock in a transaction
        return this.db.transaction(async (client) => {
            // Get order items to restore stock
            const itemsResult = await client.query(
                'SELECT product_id, quantity FROM order_items WHERE order_id = $1',
                [id]
            );

            for (const item of itemsResult.rows) {
                await client.query(
                    'UPDATE products SET stock_quantity = stock_quantity + $2, updated_at = NOW() WHERE id = $1',
                    [item.product_id, item.quantity]
                );
            }

            // Delete order (cascade deletes order_items)
            const result = await client.query(
                'DELETE FROM orders WHERE id = $1 RETURNING id',
                [id]
            );

            return result.rowCount > 0;
        });
    }
}

module.exports = OrderModel;


// ============================================================
// middleware/inputValidation.js
// ============================================================

function validateId(req, res, next) {
    const id = parseInt(req.params.id, 10);
    if (isNaN(id) || id <= 0) {
        return res.status(400).json({ error: 'Invalid ID parameter' });
    }
    req.params.id = id;
    next();
}

function validateUserInput(req, res, next) {
    const { username, email, full_name } = req.body;

    if (req.method === 'POST') {
        if (!username || typeof username !== 'string' || username.trim().length < 3) {
            return res.status(400).json({ error: 'Username must be at least 3 characters' });
        }
        if (!email || typeof email !== 'string' || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
            return res.status(400).json({ error: 'Valid email is required' });
        }
    }

    if (username !== undefined && (typeof username !== 'string' || username.trim().length < 3)) {
        return res.status(400).json({ error: 'Username must be at least 3 characters' });
    }
    if (email !== undefined && (typeof email !== 'string' || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email))) {
        return res.status(400).json({ error: 'Valid email is required' });
    }
    if (full_name !== undefined && typeof full_name !== 'string') {
        return res.status(400).json({ error: 'Full name must be a string' });
    }

    next();
}

function validateProductInput(req, res, next) {
    const { name, price, stock_quantity } = req.body;

    if (req.method === 'POST') {
        if (!name || typeof name !== 'string' || name.trim().length === 0) {
            return res.status(400).json({ error: 'Product name is required' });
        }
        if (price === undefined || typeof price !== 'number' || price < 0) {
            return res.status(400).json({ error: 'Valid price is required (>= 0)' });
        }
    }

    if (price !== undefined && (typeof price !== 'number' || price < 0)) {
        return res.status(400).json({ error: 'Price must be a non-negative number' });
    }
    if (stock_quantity !== undefined && (typeof stock_quantity !== 'number' || stock_quantity < 0 || !Number.isInteger(stock_quantity))) {
        return res.status(400).json({ error: 'Stock quantity must be a non-negative integer' });
    }

    next();
}

function validateOrderInput(req, res, next) {
    const { user_id, items } = req.body;

    if (!user_id || typeof user_id !== 'number' || user_id <= 0) {
        return res.status(400).json({ error: 'Valid user_id is required' });
    }
    if (!Array.isArray(items) || items.length === 0) {
        return res.status(400).json({ error: 'At least one order item is required' });
    }

    for (let i = 0; i < items.length; i++) {
        const item = items[i];
        if (!item.product_id || typeof item.product_id !== 'number' || item.product_id <= 0) {
            return res.status(400).json({ error: `Item ${i}: valid product_id is required` });
        }
        if (!item.quantity || typeof item.quantity !== 'number' || item.quantity <= 0 || !Number.isInteger(item.quantity)) {
            return res.status(400).json({ error: `Item ${i}: quantity must be a positive integer` });
        }
    }

    next();
}

module.exports = {
    validateId,
    validateUserInput,
    validateProductInput,
    validateOrderInput,
};


