// routes/userRoutes.js
// ============================================================

const express = require('express');

function createUserRoutes(userModel) {
    const router = express.Router();
    const { validateId, validateUserInput } = require('./middleware/inputValidation');

    router.get('/', async (req, res, next) => {
        try {
            const limit = parseInt(req.query.limit, 10) || 50;
            const offset = parseInt(req.query.offset, 10) || 0;
            const users = await userModel.findAll({ limit, offset });
            res.json({ data: users, count: users.length });
        } catch (error) {
            next(error);
        }
    });

    router.get('/:id', validateId, async (req, res, next) => {
        try {
            const user = await userModel.findById(req.params.id);
            if (!user) return res.status(404).json({ error: 'User not found' });
            res.json({ data: user });
        } catch (error) {
            next(error);
        }
    });

    router.post('/', validateUserInput, async (req, res, next) => {
        try {
            const { username, email, full_name } = req.body;
            const user = await userModel.create({ username: username.trim(), email: email.trim(), full_name: full_name?.trim() });
            res.status(201).json({ data: user });
        } catch (error) {
            if (error.code === '23505') {
                return res.status(409).json({ error: 'Username or email already exists' });
            }
            next(error);
        }
    });

    router.put('/:id', validateId, validateUserInput, async (req, res, next) => {
        try {
            const { username, email, full_name } = req.body;
            const user = await userModel.update(req.params.id, {
                username: username?.trim(),
                email: email?.trim(),
                full_name: full_name?.trim(),
            });
            if (!user) return res.status(404).json({ error: 'User not found' });
            res.json({ data: user });
        } catch (error) {
            if (error.code === '23505') {
                return res.status(409).json({ error: 'Username or email already exists' });
            }
            next(error);
        }
    });

    router.delete('/:id', validateId, async (req, res, next) => {
        try {
            const deleted = await userModel.delete(req.params.id);
            if (!deleted) return res.status(404).json({ error: 'User not found' });
            res.json({ message: 'User deleted successfully' });
        } catch (error) {
            if (error.code === '23503') {
                return res.status(409).json({ error: 'Cannot delete user with existing orders or products' });
            }
            next(error);
        }
    });

    return router;
}

module.exports = createUserRoutes;


